  orderBy: { column: string; ascending?: boolean } | null = null;
  limitValue: number | null = null;
  columns = '*';
  options: any = {};
  expect: 'many' | 'single' | 'maybeSingle' = 'many';

  constructor(table: string) {
    this.table = table;
  }

  select(columns = '*', options = {}) {
    this.columns = columns;
    this.options = { ...this.options, ...options };
    return this;
  }

  insert(values: any) {
    this.operation = 'insert';
    this.payload = values;
    return this;
  }

  upsert(values: any, options = {}) {
    this.operation = 'upsert';
    this.payload = values;
    this.options = { ...this.options, ...options };
    return this;
  }

  update(values: any) {
    this.operation = 'update';
    this.payload = values;
    return this;
  }

  delete() {
    this.operation = 'delete';
    return this;
  }

  eq(column: string, value: any) { this.filters.push({ type: 'eq', column, value }); return this; }
  is(column: string, value: any) { this.filters.push({ type: 'eq', column, value }); return this; }
  neq(column: string, value: any) { this.filters.push({ type: 'neq', column, value }); return this; }
  gt(column: string, value: any) { this.filters.push({ type: 'gt', column, value }); return this; }
  gte(column: string, value: any) { this.filters.push({ type: 'gte', column, value }); return this; }
  lt(column: string, value: any) { this.filters.push({ type: 'lt', column, value }); return this; }
  lte(column: string, value: any) { this.filters.push({ type: 'lte', column, value }); return this; }
  in(column: string, value: any[]) { this.filters.push({ type: 'in', column, value }); return this; }
  match(value: Record<string, any>) { this.filters.push({ type: 'match', value }); return this; }
  order(column: string, options = { ascending: true }) { this.orderBy = { column, ascending: options.ascending }; return this; }
  limit(limit: number) { this.limitValue = limit; return this; }
  single() { this.expect = 'single'; return this; }
  maybeSingle() { this.expect = 'maybeSingle'; return this; }

  async execute() {
    if (this.operation === 'select') {
      const result = await apiFetch('/db/query', {
        method: 'POST',
        body: JSON.stringify({
          table: this.table,
          filters: this.filters,
          order: this.orderBy,
          limit: this.limitValue,
          columns: this.columns,
          options: this.options,
        }),
      });
      if (result.error) return result;
      const rows = result.data || [];
      if (this.expect === 'single') return { data: rows[0] ?? null, error: rows[0] ? null : { message: 'Registro não encontrado.' }, count: result.count ?? null };
      if (this.expect === 'maybeSingle') return { data: rows[0] ?? null, error: null, count: result.count ?? null };
      return { data: rows, error: null, count: result.count ?? null };
    }

    const result = await apiFetch('/db/mutate', {
      method: 'POST',
      body: JSON.stringify({
        table: this.table,
        action: this.operation,
        values: this.payload,
        filters: this.filters,
        options: this.options,
      }),
    });
    if (result.error) return result;
    const rows = result.data || [];
    if (this.expect === 'single') return { data: rows[0] ?? null, error: rows[0] ? null : { message: 'Registro não encontrado.' } };
    if (this.expect === 'maybeSingle') return { data: rows[0] ?? null, error: null };
    return { data: rows, error: null };
  }

  then<TResult1 = any, TResult2 = never>(
    onfulfilled?: ((value: any) => TResult1 | PromiseLike<TResult1>) | null,
    onrejected?: ((reason: any) => TResult2 | PromiseLike<TResult2>) | null,
  ): Promise<TResult1 | TResult2> {
    return this.execute().then(onfulfilled, onrejected);
  }
