const auth = {
  async getSession() {
    const result = await apiFetch('/auth/session', { method: 'GET' });
    return { data: { session: result.session || null }, error: result.error || null };
  },
  async getUser() {
    const sessionRes = await this.getSession();
    return { data: { user: sessionRes.data.session?.user || null }, error: sessionRes.error || null };
  },
  async signInWithPassword({ email, password }: { email: string; password: string }) {
    const result = await apiFetch('/auth/login', { method: 'POST', body: JSON.stringify({ email, password }) });
    if (!result.error && result.token) writeToken(result.token);
    await emitAuth('SIGNED_IN');
    return { data: { session: result.user ? { user: result.user } : null, user: result.user || null }, error: result.error || null };
  },
  async signUp({ email, password, options }: { email: string; password: string; options?: any }) {
    const result = await apiFetch('/auth/register', { method: 'POST', body: JSON.stringify({ email, password, name: options?.data?.full_name || '' }) });
    if (!result.error && result.token) writeToken(result.token);
    await emitAuth('SIGNED_IN');
    return { data: { session: result.user ? { user: result.user } : null, user: result.user || null }, error: result.error || null };
  },
  async signOut() {
    writeToken(null);
    await emitAuth('SIGNED_OUT');
    return { error: null };
  },
  async resetPasswordForEmail(email: string, _options?: any) {
    const result = await apiFetch('/auth/reset-password', { method: 'POST', body: JSON.stringify({ email }) });
    return { data: result.data || null, error: result.error || null };
  },
  async updateUser(update: { password?: string; data?: Record<string, any> }) {
    if ((update as any).password) {
      const result = await apiFetch('/auth/update-password', { method: 'POST', body: JSON.stringify({ password: (update as any).password }) });
      return { data: result.data || null, error: result.error || null };
    }
    return { data: { user: null }, error: null };
  },
  onAuthStateChange(callback: (event: string, session: any) => void) {
    listeners.add(callback);
    return { data: { subscription: { unsubscribe: () => { listeners.delete(callback); return; } } } };
  },
};

